SELECT product_id, size_id, AVG(rating) AS average_rating
FROM fit_feedback
GROUP BY product_id, size_id;

SELECT COUNT(DISTINCT user_id) 
FROM fit_feedback 
WHERE fit_reason = 'Runs small';

SELECT DISTINCT product_id 
FROM returns 
WHERE return_date = date('now');

SELECT *
FROM returns
WHERE status = 'approved' AND MOD(return_id, 2) = 0;
